// Re-emit the original passthrough payload from the execute-workflow trigger.
// Get Project Config replaces the incoming item with the config row, so we
// restore the ticket data here for every downstream check to reference via
// $('Restore trigger data').
return $('When Executed by Another Workflow').all();

// === Email blocklist filter ===
// Mode: "Run Once for All Items".
// Input to this node = rows from the "Get Email Blocklist" Data Table node.

// 1) Requester email, from the restored trigger payload.
const email = String(
  $('Restore trigger data').first()?.json?.body?.['ticket.requester.email'] ?? ''
).trim().toLowerCase();

// 2) Blocklist rows (each input item = one row from the data table).
const rows = $input.all();

// 3) First active rule whose match_value is contained in the email wins.
let matched = null;
if (email) {
  for (const r of rows) {
    const row = r.json || {};
    const isActive = !(row.active === false || row.active === 0
      || row.active === 'false' || row.active === '0' || row.active === 'no');
    if (!isActive) continue;
    const needle = String(row.match_value ?? '').trim().toLowerCase();
    if (!needle) continue;
    if (email.includes(needle)) { matched = row; break; }
  }
}

// 4) One decision item out.
return [{
  json: {
    email,
    blocked: matched !== null,
    matched_value: matched ? matched.match_value : null,
    matched_reason: (matched && matched.reason != null) ? matched.reason : null,
  },
}];

// Statuses that mean "not yet handled by support".
// A freshly created end-user ticket lands as NEW until support engages it.
const UNHANDLED_STATUSES = ['new'];

// Current ticket id, from the restored trigger payload.
const currentTicketId = $('Restore trigger data').first().json.body['ticket.id'];

const tickets = $input.first().json.tickets || [];

const otherUnhandledTickets = tickets.filter(
  t => UNHANDLED_STATUSES.includes(t.status) && String(t.id) !== String(currentTicketId)
);

// proceed = this is effectively the only unhandled ticket for the requester
const proceed = otherUnhandledTickets.length === 0;

return [{
  json: {
    proceed,
    unhandled_ticket_count: otherUnhandledTickets.length,
    other_unhandled_ticket_ids: otherUnhandledTickets.map(t => t.id)
  }
}];

